<?php

namespace App\Http\Controllers;

use Illuminate\Http\Request;
use Illuminate\Support\Facades\DB;

class ProductSearchController extends Controller
{
    /**
     * Search for products based on name, category, and price range.
     *
     * @param  \Illuminate\Http\Request  $request
     * @return \Illuminate\Http\JsonResponse
     */
    public function searchProducts(Request $request)
    {
        $name = $request->input('name');
        $category = $request->input('category');
        $minPrice = $request->input('min_price');
        $maxPrice = $request->input('max_price');

        $baseQuery = "SELECT * FROM products";
        $conditions = [];
        $bindings = [];

        if ($name) {
            $conditions[] = "name LIKE ?";
            $bindings[] = '%' . $name . '%';
        }

        if ($category) {
            $conditions[] = "category = ?";
            $bindings[] = $category;
        }

        if ($minPrice !== null) {
            $conditions[] = "price >= ?";
            $bindings[] = $minPrice;
        }

        if ($maxPrice !== null) {
            $conditions[] = "price <= ?";
            $bindings[] = $maxPrice;
        }

        if (!empty($conditions)) {
            $baseQuery .= " WHERE " . implode(" AND ", $conditions);
        }

        // Add ordering for consistent results, e.g., by product name
        $baseQuery .= " ORDER BY name ASC";

        // Execute the raw query using DB::select and DB::raw
        $products = DB::select(DB::raw($baseQuery), $bindings);

        return response()->json($products);
    }
}